import { api as http } from "../uiApiCompat";
import { usePoll } from "../hooks/usePoll";
import { useAppStore } from "../store/appStore";
import AIExplainButton from "../../components/AIExplainButton";
import V2EmptyState from "../components/V2EmptyState";

/* ── helpers ─────────────────────────────────────────── */
const fmtPct = (v) => v == null ? "--" : `${(v * 100).toFixed(1)}%`;
const tonePct = (v) => v == null ? "blue" : v > 0.8 ? "green" : v > 0.6 ? "amber" : "red";

/* ── stat card ───────────────────────────────────────── */
function Stat({ label, value, tone = "blue", sub = "" }) {
  return (
    <div className="v2-card">
      <div className="v2-ct">{label}</div>
      <div className={`v2-cv v2-${tone}`}>{value}</div>
      {sub && <div className="v2-muted" style={{ marginTop: 8 }}>{sub}</div>}
    </div>
  );
}

/* ── SVG confidence gauge ────────────────────────────── */
function ConfidenceGauge({ value }) {
  const pct = Math.max(0, Math.min(1, value ?? 0));
  const angle = -90 + pct * 180;
  const color = pct > 0.8 ? "var(--v2-green)" : pct > 0.6 ? "var(--v2-amber)" : "var(--v2-red)";
  const rad = (a) => (a * Math.PI) / 180;
  const r = 60;
  const cx = 80, cy = 75;
  /* arc path from -90 to angle */
  const startX = cx + r * Math.cos(rad(-90));
  const startY = cy + r * Math.sin(rad(-90));
  const endX = cx + r * Math.cos(rad(angle));
  const endY = cy + r * Math.sin(rad(angle));
  const largeArc = pct > 0.5 ? 1 : 0;

  return (
    <svg viewBox="0 0 160 100" style={{ width: "100%", maxWidth: 220, display: "block", margin: "0 auto" }}>
      {/* background arc */}
      <path d={`M ${cx + r * Math.cos(rad(-90))} ${cy + r * Math.sin(rad(-90))} A ${r} ${r} 0 1 1 ${cx + r * Math.cos(rad(90))} ${cy + r * Math.sin(rad(90))}`}
        fill="none" stroke="rgba(255,255,255,0.08)" strokeWidth="10" strokeLinecap="round" />
      {/* value arc */}
      {pct > 0 && (
        <path d={`M ${startX} ${startY} A ${r} ${r} 0 ${largeArc} 1 ${endX} ${endY}`}
          fill="none" stroke={color} strokeWidth="10" strokeLinecap="round" />
      )}
      {/* center text */}
      <text x={cx} y={cy - 8} textAnchor="middle" fill={color} fontSize="22" fontWeight="700" fontFamily="monospace">
        {(pct * 100).toFixed(0)}%
      </text>
      <text x={cx} y={cy + 10} textAnchor="middle" fill="rgba(255,255,255,0.45)" fontSize="10">
        Confidence
      </text>
    </svg>
  );
}

/* ── main page ───────────────────────────────────────── */
export default function Explainability() {
  const { state } = useAppStore();

  const { data: mlData, loading } = usePoll(
    async () => { const r = await http.get("/ml/models/performance"); return r.data; },
    { intervalMs: 30000, enabled: !state.offlineMode }
  );

  const features = mlData?.feature_importance ?? [];
  const rawMetrics = mlData?.model_metrics ?? mlData?.metrics ?? null;
  /* normalise metric field names to match what the UI expects */
  const metrics = rawMetrics ? {
    ...rawMetrics,
    f1: rawMetrics.f1 ?? rawMetrics.f1_score ?? null,
    version: rawMetrics.version ?? mlData?.model_version ?? null,
    last_trained: rawMetrics.last_trained ?? (mlData?.last_trained
      ? new Date(mlData.last_trained * 1000).toISOString().slice(0, 10)
      : null),
    /* Use accuracy as confidence proxy when confidence isn't available */
    confidence: rawMetrics.confidence ?? rawMetrics.avg_confidence ?? rawMetrics.auc_roc ?? null,
  } : null;
  const rawPerStrategy = mlData?.per_strategy ?? [];
  const perStrategy = rawPerStrategy.map(s => ({
    ...s,
    name: s.name ?? s.strategy,
    status: s.status ?? "ACTIVE",
    predictions: s.predictions ?? s.count ?? s.train_samples ?? null,
    confidence: s.confidence ?? s.auc_roc ?? null,
  }));
  const confidence = metrics?.confidence ?? null;
  const topFeature = features.length > 0 ? features[0] : null;

  /* sort features by absolute importance */
  const sortedFeatures = [...features].sort((a, b) => Math.abs(b.importance ?? b.value ?? 0) - Math.abs(a.importance ?? a.value ?? 0));
  const maxImportance = sortedFeatures.length > 0 ? (Math.max(...sortedFeatures.map(f => Math.abs(f.importance ?? f.value ?? 0))) || 1) : 1;

  /* metric tiles */
  const metricTiles = metrics ? [
    { label: "Accuracy", value: fmtPct(metrics.accuracy), tone: tonePct(metrics.accuracy) },
    { label: "Precision", value: fmtPct(metrics.precision), tone: tonePct(metrics.precision) },
    { label: "Recall", value: fmtPct(metrics.recall), tone: tonePct(metrics.recall) },
    { label: "F1 Score", value: metrics.f1 != null ? metrics.f1.toFixed(3) : "--", tone: metrics.f1 > 0.8 ? "green" : "amber" },
    { label: "AUC-ROC", value: metrics.auc_roc != null ? metrics.auc_roc.toFixed(3) : "--", tone: metrics.auc_roc > 0.8 ? "green" : "amber" },
    { label: "Log Loss", value: metrics.log_loss != null ? metrics.log_loss.toFixed(4) : "--", tone: metrics.log_loss < 0.4 ? "green" : "amber" },
  ] : [];

  if (loading) {
    return (
      <>
        <div className="v2-pagehead">
          <div>
            <h1 className="v2-h1">Model Explainability</h1>
            <div className="v2-muted">Loading model data...</div>
          </div>
        </div>
        <div className="v2-grid">
          {[1, 2, 3, 4].map(i => (
            <div key={i} className="v2-card">
              <div className="v2-ct">Loading...</div>
              <div className="v2-cv v2-blue" style={{ opacity: 0.3 }}>--</div>
            </div>
          ))}
        </div>
      </>
    );
  }

  return (
    <>
      <div className="v2-pagehead">
        <div>
          <h1 className="v2-h1">Model Explainability</h1>
          <div className="v2-muted">Feature attribution and predictive confidence (SHAP/LIME style panels).</div>
        </div>
        <div className="v2-row">
          <AIExplainButton explainType="ml" refId="general" label="AI Explain" />
        </div>
      </div>

      {/* ── Top Stats ──────────────────────────────────── */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <Stat label="Top Feature" value={topFeature ? topFeature.name ?? topFeature.feature ?? "--" : "--"} tone="blue"
          sub={topFeature ? `Importance: ${(topFeature.importance ?? topFeature.value ?? 0).toFixed(3)}` : "No SHAP data"} />
        <Stat label="Prediction Confidence" value={confidence != null ? `${(confidence * 100).toFixed(1)}%` : "--"}
          tone={confidence != null ? tonePct(confidence) : "blue"} sub={confidence != null ? "Avg model confidence" : "No model output"} />
        <Stat label="Model Version" value={metrics?.version ?? metrics?.model_version ?? "--"} tone="blue"
          sub={metrics?.last_trained ? `Trained ${metrics.last_trained}` : "No model selected"} />
        <Stat label="Features Used" value={features.length > 0 ? features.length : "--"} tone="blue"
          sub={features.length > 0 ? "Input features" : "No analysis run"} />
      </div>

      <div className="v2-grid">
        {/* ── SHAP Feature Attribution Bar Chart ──────── */}
        <div className="v2-card wide">
          <div className="v2-ct">Feature Attribution (SHAP)</div>
          {sortedFeatures.length === 0 ? (
            <V2EmptyState icon={"\u29C6"} title="No Feature Attribution Data" message="SHAP feature attribution chart will appear when a model produces explainability output." />
          ) : (
            <div style={{ marginTop: 12 }}>
              {sortedFeatures.slice(0, 15).map((f, i) => {
                const val = f.importance ?? f.value ?? 0;
                const absVal = Math.abs(val);
                const pct = (absVal / maxImportance) * 100;
                const isPositive = val >= 0;
                return (
                  <div key={f.name ?? f.feature ?? i} style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8 }}>
                    <span style={{ width: 120, fontSize: 11, textAlign: "right", flexShrink: 0, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                      {f.name ?? f.feature}
                    </span>
                    <div style={{ flex: 1, display: "flex", alignItems: "center" }}>
                      <div style={{ width: "50%", display: "flex", justifyContent: "flex-end" }}>
                        {!isPositive && (
                          <div style={{
                            height: 14, width: `${pct}%`, borderRadius: "3px 0 0 3px",
                            background: "linear-gradient(90deg, rgba(255,120,120,0.2), rgba(255,120,120,0.7))",
                          }} />
                        )}
                      </div>
                      <div style={{ width: 1, height: 18, background: "rgba(255,255,255,0.15)" }} />
                      <div style={{ width: "50%", display: "flex" }}>
                        {isPositive && (
                          <div style={{
                            height: 14, width: `${pct}%`, borderRadius: "0 3px 3px 0",
                            background: "linear-gradient(90deg, rgba(110,240,180,0.7), rgba(110,240,180,0.2))",
                          }} />
                        )}
                      </div>
                    </div>
                    <span className="v2-mono" style={{ width: 60, fontSize: 10, flexShrink: 0, color: isPositive ? "var(--v2-green)" : "var(--v2-red)" }}>
                      {val >= 0 ? "+" : ""}{val.toFixed(3)}
                    </span>
                  </div>
                );
              })}
              <div className="v2-row" style={{ justifyContent: "center", marginTop: 8 }}>
                <span className="v2-muted" style={{ fontSize: 10 }}>{"\u2190"} Negative Impact</span>
                <span style={{ width: 40 }} />
                <span className="v2-muted" style={{ fontSize: 10 }}>Positive Impact {"\u2192"}</span>
              </div>
            </div>
          )}
        </div>

        {/* ── Model Metrics Dashboard (6 tiles) ──────── */}
        <div className="v2-card half">
          <div className="v2-ct">Model Metrics</div>
          {metricTiles.length === 0 ? (
            <V2EmptyState icon={"\u29C6"} title="No Metrics" message="Model performance metrics will appear when model output is available." />
          ) : (
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12, marginTop: 12 }}>
              {metricTiles.map(m => (
                <div key={m.label} style={{
                  padding: "10px 12px", borderRadius: 10,
                  background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.06)",
                }}>
                  <div className="v2-muted" style={{ fontSize: 10, marginBottom: 4 }}>{m.label}</div>
                  <div className={`v2-mono v2-${m.tone}`} style={{ fontSize: 18, fontWeight: 700 }}>{m.value}</div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* ── Confidence Gauge ────────────────────────── */}
        <div className="v2-card half">
          <div className="v2-ct">Prediction Confidence</div>
          {confidence == null ? (
            <V2EmptyState icon={"\u29C6"} title="No Confidence Data" message="Confidence gauge will appear when model predictions are available." />
          ) : (
            <div style={{ marginTop: 12 }}>
              <ConfidenceGauge value={confidence} />
              <div style={{ display: "flex", justifyContent: "space-between", marginTop: 12, padding: "0 10px" }}>
                <div>
                  <div className="v2-muted" style={{ fontSize: 10 }}>Min</div>
                  <div className="v2-mono" style={{ fontSize: 13 }}>{fmtPct(metrics?.min_confidence ?? confidence * 0.7)}</div>
                </div>
                <div style={{ textAlign: "center" }}>
                  <div className="v2-muted" style={{ fontSize: 10 }}>Average</div>
                  <div className="v2-mono" style={{ fontSize: 13 }}>{fmtPct(confidence)}</div>
                </div>
                <div style={{ textAlign: "right" }}>
                  <div className="v2-muted" style={{ fontSize: 10 }}>Max</div>
                  <div className="v2-mono" style={{ fontSize: 13 }}>{fmtPct(metrics?.max_confidence ?? Math.min(1, confidence * 1.2))}</div>
                </div>
              </div>
            </div>
          )}
        </div>

        {/* ── Per-Strategy Performance Table ──────────── */}
        <div className="v2-card wide">
          <div className="v2-ct">Per-Strategy Model Performance</div>
          {perStrategy.length === 0 ? (
            <V2EmptyState icon={"\u29C6"} title="No Strategy Data" message="Per-strategy model performance will appear when per-strategy analysis is available." />
          ) : (
            <div className="v2-table" style={{ marginTop: 8 }}>
              <div className="v2-thead" style={{ gridTemplateColumns: "160px 90px 90px 90px 90px 90px 80px" }}>
                <span>Strategy</span>
                <span>Accuracy</span>
                <span>Precision</span>
                <span>Recall</span>
                <span>Confidence</span>
                <span>Predictions</span>
                <span>Status</span>
              </div>
              {perStrategy.map(s => (
                <div key={s.strategy ?? s.name} className="v2-tr" style={{ gridTemplateColumns: "160px 90px 90px 90px 90px 90px 80px" }}>
                  <span style={{ fontWeight: 600 }}>{s.strategy ?? s.name}</span>
                  <span className={`v2-mono v2-${tonePct(s.accuracy)}`}>{fmtPct(s.accuracy)}</span>
                  <span className={`v2-mono v2-${tonePct(s.precision)}`}>{fmtPct(s.precision)}</span>
                  <span className={`v2-mono v2-${tonePct(s.recall)}`}>{fmtPct(s.recall)}</span>
                  <span className={`v2-mono v2-${tonePct(s.confidence)}`}>{fmtPct(s.confidence)}</span>
                  <span className="v2-mono">{s.predictions ?? s.count ?? "--"}</span>
                  <span className={`v2-${s.status === "ACTIVE" ? "green" : "muted"}`} style={{ fontSize: 11, fontWeight: 600 }}>
                    {s.status ?? "ACTIVE"}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </>
  );
}
